# Svelte/SvelteKit Application Architecture

## Recommended Folder Structure
```
src/
├── lib/                     # Reusable code
│   ├── components/
│   │   ├── ui/
│   │   │   ├── Button.svelte
│   │   │   └── Input.svelte
│   │   └── layout/
│   ├── stores/              # Svelte stores
│   │   ├── auth.ts
│   │   └── app.ts
│   ├── services/            # API services
│   │   └── api.ts
│   ├── utils/
│   └── types/
├── routes/                  # SvelteKit pages
│   ├── +layout.svelte
│   ├── +page.svelte
│   ├── auth/
│   │   ├── login/+page.svelte
│   │   └── register/+page.svelte
│   └── api/                 # API routes
│       └── users/+server.ts
├── app.html
└── app.css
```

## Store Pattern
```typescript
// lib/stores/auth.ts
import { writable, derived } from 'svelte/store';
import { browser } from '$app/environment';

function createAuthStore() {
  const { subscribe, set, update } = writable({
    user: null,
    token: browser ? localStorage.getItem('token') : null
  });

  return {
    subscribe,
    login: async (email: string, password: string) => {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        body: JSON.stringify({ email, password })
      });
      const data = await res.json();
      set({ user: data.user, token: data.token });
      if (browser) localStorage.setItem('token', data.token);
    },
    logout: () => {
      set({ user: null, token: null });
      if (browser) localStorage.removeItem('token');
    }
  };
}

export const auth = createAuthStore();
export const isAuthenticated = derived(auth, $auth => !!$auth.user);
```

## Server Load Functions
```typescript
// routes/users/+page.server.ts
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ fetch, cookies }) => {
  const token = cookies.get('token');
  const res = await fetch('/api/users', {
    headers: { Authorization: `Bearer ${token}` }
  });
  return { users: await res.json() };
};
```

# Svelte Debugging Guide

## Reactivity Not Working

### Problem
Variable changes but UI doesn't update.

### Solutions
```svelte
<script>
  // BAD: Array mutation not detected
  let items = [];
  function addItem(item) {
    items.push(item);  // Won't trigger update!
  }

  // GOOD: Reassignment triggers reactivity
  function addItem(item) {
    items = [...items, item];
    // Or: items = items.concat(item);
  }

  // BAD: Object property change
  let user = { name: 'John' };
  user.name = 'Jane';  // Won't trigger!

  // GOOD: Reassign object
  user = { ...user, name: 'Jane' };
</script>
```

## Store Subscription Leaks

```svelte
<script>
  import { auth } from '$lib/stores/auth';

  // BAD: Manual subscription without cleanup
  let user;
  auth.subscribe(value => user = value.user);  // Memory leak!

  // GOOD: Use $ auto-subscription
  $: user = $auth.user;  // Auto-unsubscribes!

  // Or use onDestroy for manual
  import { onDestroy } from 'svelte';
  const unsubscribe = auth.subscribe(...);
  onDestroy(unsubscribe);
</script>
```

## SSR Errors

```typescript
// BAD: Browser APIs during SSR
import { browser } from '$app/environment';

// This runs on server too!
const width = window.innerWidth;  // Error!

// GOOD: Check browser environment
let width = 0;
if (browser) {
  width = window.innerWidth;
}

// Or use onMount (client-only)
import { onMount } from 'svelte';
onMount(() => {
  width = window.innerWidth;
});
```

# Next.js Application Architecture

## App Router Structure (Next.js 13+)
```
app/
├── (auth)/                  # Route group
│   ├── login/page.tsx
│   └── register/page.tsx
├── (dashboard)/
│   ├── layout.tsx
│   └── page.tsx
├── api/                     # API routes
│   └── users/route.ts
├── layout.tsx               # Root layout
├── page.tsx                 # Home page
└── globals.css
components/
├── ui/
└── features/
lib/
├── api.ts
└── utils.ts
hooks/
store/
types/
```

## Server Components Pattern
```typescript
// app/users/page.tsx (Server Component by default)
async function UsersPage() {
  const users = await fetch('https://api.example.com/users', {
    cache: 'no-store'  // or 'force-cache', next: { revalidate: 60 }
  }).then(r => r.json());

  return (
    <div>
      {users.map(user => <UserCard key={user.id} user={user} />)}
    </div>
  );
}

// Client component (needs interactivity)
'use client';
import { useState } from 'react';

export function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}
```

## API Routes
```typescript
// app/api/users/route.ts
import { NextResponse } from 'next/server';

export async function GET() {
  const users = await db.user.findMany();
  return NextResponse.json(users);
}

export async function POST(request: Request) {
  const body = await request.json();
  const user = await db.user.create({ data: body });
  return NextResponse.json(user, { status: 201 });
}
```

# Next.js Debugging Guide

## Hydration Errors

### Problem
`Hydration failed because the initial UI does not match what was rendered on the server`

### Solutions
```typescript
// BAD: Different content server vs client
function Component() {
  return <div>{new Date().toLocaleString()}</div>;  // Different on server!
}

// GOOD: Use useEffect for client-only
'use client';
function Component() {
  const [date, setDate] = useState<string>();

  useEffect(() => {
    setDate(new Date().toLocaleString());
  }, []);

  return <div>{date}</div>;
}

// GOOD: Suppress hydration warning
<time suppressHydrationWarning>
  {new Date().toLocaleString()}
</time>

// GOOD: Dynamic import with ssr: false
import dynamic from 'next/dynamic';
const ClientOnlyComponent = dynamic(
  () => import('./ClientComponent'),
  { ssr: false }
);
```

## Server Component Errors

```typescript
// BAD: Using hooks in server component
// app/page.tsx (server component)
import { useState } from 'react';  // Error!

// GOOD: Mark as client component
'use client';
import { useState } from 'react';  // Now works

// BAD: Passing functions to client components
// Server component
export default function Page() {
  const handleClick = () => console.log('clicked');
  return <ClientButton onClick={handleClick} />;  // Error!
}

// GOOD: Define handler in client component
'use client';
export function ClientButton() {
  return <button onClick={() => console.log('clicked')}>Click</button>;
}
```

## Caching Issues

```typescript
// Force fresh data
fetch(url, { cache: 'no-store' });

// Revalidate every 60 seconds
fetch(url, { next: { revalidate: 60 } });

// Revalidate on-demand
import { revalidatePath, revalidateTag } from 'next/cache';

export async function POST() {
  await updateData();
  revalidatePath('/dashboard');
  revalidateTag('users');
}
```
